import{_ as a,c as s,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Compresión de Contexto: Sesiones Largas Estables | Antigravity-Manager","description":"Aprende el mecanismo de compresión de contexto de tres capas de Antigravity. Reduce errores 400 y fallos por prompts demasiado largos mediante recorte de rondas de herramientas, compresión de Thinking y caché de firmas.","frontmatter":{"title":"Compresión de Contexto: Sesiones Largas Estables | Antigravity-Manager","sidebarTitle":"Sesiones Largas Estables","subtitle":"Compresión de Contexto: Sesiones Largas Estables","description":"Aprende el mecanismo de compresión de contexto de tres capas de Antigravity. Reduce errores 400 y fallos por prompts demasiado largos mediante recorte de rondas de herramientas, compresión de Thinking y caché de firmas.","tags":["compresión de contexto","caché de firmas","Thinking","Tool Result","estabilidad"],"prerequisite":["start-proxy-and-first-client","advanced-monitoring"],"order":8},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/advanced/context-compression/index.md","filePath":"es/lbjlaq/Antigravity-Manager/advanced/context-compression/index.md"}'),o={name:"es/lbjlaq/Antigravity-Manager/advanced/context-compression/index.md"};function t(n,e,d,c,l,p){return r(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="estabilidad-de-sesiones-largas-compresion-de-contexto-cache-de-firmas-y-compresion-de-resultados-de-herramientas" tabindex="-1">Estabilidad de Sesiones Largas: Compresión de Contexto, Caché de Firmas y Compresión de Resultados de Herramientas <a class="header-anchor" href="#estabilidad-de-sesiones-largas-compresion-de-contexto-cache-de-firmas-y-compresion-de-resultados-de-herramientas" aria-label="Permalink to &quot;Estabilidad de Sesiones Largas: Compresión de Contexto, Caché de Firmas y Compresión de Resultados de Herramientas&quot;">​</a></h1><p>Al usar clientes como Claude Code o Cherry Studio para sesiones largas, lo más molesto no es que el modelo no sea suficientemente inteligente, sino que la conversación de repente comienza a mostrar errores: <code>Prompt is too long</code>, errores de firma 400, cadenas de llamadas a herramientas rotas, o bucles de herramientas que se vuelven cada vez más lentos.</p><p>Esta lección explica claramente tres cosas que Antigravity Tools ha hecho para resolver estos problemas: compresión de contexto (intervención progresiva en tres capas), caché de firmas (para mantener la cadena de firmas de Thinking) y compresión de resultados de herramientas (para evitar que la salida de herramientas sature el contexto).</p><h2 id="lo-que-podras-hacer-despues-de-esta-leccion" tabindex="-1">Lo Que Podrás Hacer Después de Esta Lección <a class="header-anchor" href="#lo-que-podras-hacer-despues-de-esta-leccion" aria-label="Permalink to &quot;Lo Que Podrás Hacer Después de Esta Lección&quot;">​</a></h2><ul><li>Explicar claramente qué hace cada una de las tres capas de compresión progresiva de contexto y sus respectivos costos</li><li>Saber qué cosas se almacenan en el caché de firmas (tres capas: Tool/Family/Session) y el impacto del TTL de 2 horas</li><li>Entender las reglas de compresión de resultados de herramientas: cuándo se eliminan imágenes base64 y cuándo las instantáneas del navegador se convierten en resúmenes de encabezado+cuerpo</li><li>Ajustar los puntos de disparo de compresión mediante los interruptores de umbral en <code>proxy.experimental</code> cuando sea necesario</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu Situación Actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu Situación Actual&quot;">​</a></h2><ul><li>Después de conversaciones largas, comienzan a aparecer errores 400: parece una firma caducada, pero no sabes de dónde viene ni dónde se perdió</li><li>Las llamadas a herramientas aumentan, el historial de tool_result se acumula y el upstream lo rechaza directamente (o se vuelve extremadamente lento)</li><li>Quieres usar compresión como solución de emergencia, pero te preocupas por romper Prompt Cache, afectar la consistencia o hacer que el modelo pierda información</li></ul><h2 id="cuando-usar-este-enfoque" tabindex="-1">Cuándo Usar Este Enfoque <a class="header-anchor" href="#cuando-usar-este-enfoque" aria-label="Permalink to &quot;Cuándo Usar Este Enfoque&quot;">​</a></h2><ul><li>Estás ejecutando tareas con cadenas largas de herramientas (búsqueda/lectura de archivos/instantáneas del navegador/bucles de múltiples rondas de herramientas)</li><li>Estás usando modelos Thinking para razonamiento complejo y las sesiones a menudo exceden varias docenas de rondas</li><li>Estás investigando problemas de estabilidad que se reproducen en el cliente pero no puedes explicar por qué</li></ul><h2 id="que-es-la-compresion-de-contexto" tabindex="-1">Qué Es la Compresión de Contexto <a class="header-anchor" href="#que-es-la-compresion-de-contexto" aria-label="Permalink to &quot;Qué Es la Compresión de Contexto&quot;">​</a></h2><p><strong>Compresión de contexto</strong> es la reducción de ruido y adelgazamiento automático que el agente realiza en mensajes históricos cuando detecta que la presión del contexto es demasiado alta: primero elimina rondas antiguas de herramientas, luego comprime el texto Thinking antiguo en marcadores de posición pero preserva las firmas, y finalmente en casos extremos genera resúmenes XML y Fork de una nueva sesión para continuar la conversación, reduciendo así fallos causados por <code>Prompt is too long</code> y roturas de cadenas de firmas.</p><div class="info custom-block"><p class="custom-block-title">¿Cómo se calcula la presión del contexto?</p><p>El procesador de Claude usa <code>ContextManager::estimate_token_usage()</code> para hacer una estimación ligera, la calibra con <code>estimation_calibrator</code>, y luego obtiene el porcentaje de presión con <code>usage_ratio = estimated_usage / context_limit</code> (el registro imprimirá los valores raw/calibrated).</p></div><h2 id="🎒-preparativos-antes-de-empezar" tabindex="-1">🎒 Preparativos Antes de Empezar <a class="header-anchor" href="#🎒-preparativos-antes-de-empezar" aria-label="Permalink to &quot;🎒 Preparativos Antes de Empezar&quot;">​</a></h2><ul><li>Ya has ejecutado el agente local y el cliente definitivamente está usando la ruta <code>/v1/messages</code> (ver &quot;Iniciar el proxy inverso local y conectar el primer cliente&quot;)</li><li>Puedes ver los registros del agente (depuración del desarrollador o archivos de registro locales). El plan de pruebas en el repositorio proporciona una ruta de registro de ejemplo y un método grep (ver <code>docs/testing/context_compression_test_plan.md</code>)</li></ul><div class="tip custom-block"><p class="custom-block-title">Mejor localización con Proxy Monitor</p><p>Si quieres correlacionar el disparo de compresión con qué tipo de solicitud/qué cuenta/qué ronda de llamada a herramienta, se recomienda tener Proxy Monitor abierto simultáneamente.</p></div><h2 id="idea-central" tabindex="-1">Idea Central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea Central&quot;">​</a></h2><p>Este diseño de estabilidad no elimina todo el historial directamente, sino que interviene capa por capa de menor a mayor costo:</p><table tabindex="0"><thead><tr><th>Capa</th><th>Punto de disparo (configurable)</th><th>Qué hace</th><th>Costo/efectos secundarios</th></tr></thead><tbody><tr><td>Layer 1</td><td><code>proxy.experimental.context_compression_threshold_l1</code> (por defecto 0.4)</td><td>Identifica rondas de herramientas, solo conserva las N rondas más recientes (en el código es 5), elimina pares tool_use/tool_result anteriores</td><td>No modifica el contenido de los mensajes restantes, más amigable con Prompt Cache</td></tr><tr><td>Layer 2</td><td><code>proxy.experimental.context_compression_threshold_l2</code> (por defecto 0.55)</td><td>Comprime el texto Thinking antiguo en <code>&quot;...&quot;</code>, pero preserva <code>signature</code>, y protege los últimos 4 mensajes sin modificar</td><td>Modifica el contenido histórico, los comentarios indican explícitamente que romperá el caché, pero puede mantener la cadena de firmas</td></tr><tr><td>Layer 3</td><td><code>proxy.experimental.context_compression_threshold_l3</code> (por defecto 0.7)</td><td>Llama al modelo en segundo plano para generar resúmenes XML, luego Fork una nueva secuencia de mensajes para continuar la conversación</td><td>Depende de llamadas al modelo en segundo plano; si falla, devolverá 400 (con indicación amigable)</td></tr></tbody></table><p>A continuación, desglosaré las tres capas y explicaré el caché de firmas y la compresión de resultados de herramientas junto con ellas.</p><h3 id="layer-1-recorte-de-rondas-de-herramientas-trim-tool-messages" tabindex="-1">Layer 1: Recorte de Rondas de Herramientas (Trim Tool Messages) <a class="header-anchor" href="#layer-1-recorte-de-rondas-de-herramientas-trim-tool-messages" aria-label="Permalink to &quot;Layer 1: Recorte de Rondas de Herramientas (Trim Tool Messages)&quot;">​</a></h3><p>El punto clave de Layer 1 es solo eliminar rondas completas de interacción con herramientas, evitando la eliminación parcial que cause inconsistencias en el contexto.</p><ul><li>La regla para identificar una ronda de interacción con herramientas está en <code>identify_tool_rounds()</code>: cuando aparece <code>tool_use</code> en <code>assistant</code> comienza una ronda, las apariciones subsiguientes de <code>tool_result</code> en <code>user</code> todavía cuentan como parte de esta ronda, hasta encontrar texto user normal para terminar la ronda.</li><li>La ejecución real del recorte está en <code>ContextManager::trim_tool_messages(&amp;mut messages, 5)</code>: cuando las rondas históricas de herramientas exceden 5 rondas, elimina los mensajes involucrados en rondas anteriores.</li></ul><h3 id="layer-2-compresion-de-thinking-pero-preservacion-de-firmas" tabindex="-1">Layer 2: Compresión de Thinking Pero Preservación de Firmas <a class="header-anchor" href="#layer-2-compresion-de-thinking-pero-preservacion-de-firmas" aria-label="Permalink to &quot;Layer 2: Compresión de Thinking Pero Preservación de Firmas&quot;">​</a></h3><p>Muchos problemas 400 no son porque Thinking sea demasiado largo, sino porque la cadena de firmas de Thinking está rota. La estrategia de Layer 2 es:</p><ul><li>Solo procesa <code>ContentBlock::Thinking { thinking, signature, .. }</code> en mensajes <code>assistant</code></li><li>Solo comprime cuando <code>signature.is_some()</code> y <code>thinking.len() &gt; 10</code>, cambiando <code>thinking</code> directamente a <code>&quot;...&quot;</code></li><li>Los últimos <code>protected_last_n = 4</code> mensajes no se comprimen (aproximadamente las últimas 2 rondas de user/assistant)</li></ul><p>Esto ahorra muchos tokens, pero mantiene <code>signature</code> en el historial, evitando que la cadena de herramientas no tenga forma de recuperarse cuando necesite retroalimentar firmas.</p><h3 id="layer-3-fork-resumen-xml-ultimo-recurso" tabindex="-1">Layer 3: Fork + Resumen XML (Último Recurso) <a class="header-anchor" href="#layer-3-fork-resumen-xml-ultimo-recurso" aria-label="Permalink to &quot;Layer 3: Fork + Resumen XML (Último Recurso)&quot;">​</a></h3><p>Cuando la presión continúa aumentando, el procesador de Claude intentará reiniciar la sesión sin perder información clave:</p><ol><li>Extrae la última firma válida de Thinking de los mensajes originales (<code>ContextManager::extract_last_valid_signature()</code>)</li><li>Concatena todo el historial + <code>CONTEXT_SUMMARY_PROMPT</code> en una solicitud para generar un resumen XML, el modelo se fija como <code>BACKGROUND_MODEL_LITE</code> (en el código actual es <code>gemini-2.5-flash</code>)</li><li>El resumen debe incluir <code>&lt;latest_thinking_signature&gt;</code>, usado para la continuación posterior de la cadena de firmas</li><li>Fork de una nueva secuencia de mensajes: <ul><li><code>User: Context has been compressed... + XML summary</code></li><li><code>Assistant: I have reviewed...</code></li><li>Y adjunta el último mensaje user de la solicitud original (si no es la instrucción de resumen recién creada)</li></ul></li></ol><p>Si Fork + resumen falla, devolverá directamente <code>StatusCode::BAD_REQUEST</code>, y te sugerirá usar <code>/compact</code> o <code>/clear</code> para procesar manualmente (ver el error JSON devuelto por el procesador).</p><h3 id="derivacion-1-cache-de-firmas-de-tres-capas-tool-family-session" tabindex="-1">Derivación 1: Caché de Firmas de Tres Capas (Tool / Family / Session) <a class="header-anchor" href="#derivacion-1-cache-de-firmas-de-tres-capas-tool-family-session" aria-label="Permalink to &quot;Derivación 1: Caché de Firmas de Tres Capas (Tool / Family / Session)&quot;">​</a></h3><p>El caché de firmas es el fusible de la compresión de contexto, especialmente cuando el cliente recorta/descarta campos de firma.</p><ul><li>TTL: <code>SIGNATURE_TTL = 2 * 60 * 60</code> (2 horas)</li><li>Layer 1: <code>tool_use_id -&gt; signature</code> (recuperación de cadena de herramientas)</li><li>Layer 2: <code>signature -&gt; model family</code> (verificación de compatibilidad entre modelos, evitando que las firmas de Claude se lleven a modelos de la familia Gemini)</li><li>Layer 3: <code>session_id -&gt; latest signature</code> (aislamiento a nivel de sesión, evitando contaminación entre diferentes conversaciones)</li></ul><p>Estas tres capas de caché se escriben/leen durante el análisis de flujo SSE de Claude y la conversión de solicitudes:</p><ul><li>Al analizar el flujo hacia <code>signature</code> en thinking, se escribe en Session Cache (y caché de family)</li><li>Al analizar el flujo hacia <code>signature</code> en tool_use, se escribe en Tool Cache + Session Cache</li><li>Al convertir llamadas a herramientas de Claude a <code>functionCall</code> de Gemini, se prioriza recuperar la firma de Session Cache o Tool Cache</li></ul><h3 id="derivacion-2-compresor-de-resultados-de-herramientas-tool-result-compressor" tabindex="-1">Derivación 2: Compresor de Resultados de Herramientas (Tool Result Compressor) <a class="header-anchor" href="#derivacion-2-compresor-de-resultados-de-herramientas-tool-result-compressor" aria-label="Permalink to &quot;Derivación 2: Compresor de Resultados de Herramientas (Tool Result Compressor)&quot;">​</a></h3><p>Los resultados de herramientas tienden a saturar el contexto más fácilmente que el texto de chat, por lo que en la fase de conversión de solicitudes se hace una reducción predecible de tool_result.</p><p>Reglas principales (todas en <code>tool_result_compressor.rs</code>):</p><ul><li>Límite total de caracteres: <code>MAX_TOOL_RESULT_CHARS = 200_000</code></li><li>Bloques de imágenes base64 se eliminan directamente (se agrega un texto de aviso)</li><li>Si se detecta una indicación de que la salida se guardó en un archivo, se extrae información clave y se usa un marcador <code>[tool_result omitted ...]</code></li><li>Si se detecta una instantánea del navegador (contiene características como <code>page snapshot</code> / <code>ref=</code>), se convierte en resumen de encabezado+cuerpo, marcando cuántos caracteres se omitieron</li><li>Si la entrada parece HTML, primero se eliminan fragmentos <code>&lt;style&gt;</code>/<code>&lt;script&gt;</code>/base64 antes de truncar</li></ul><h2 id="sigueme" tabindex="-1">Sígueme <a class="header-anchor" href="#sigueme" aria-label="Permalink to &quot;Sígueme&quot;">​</a></h2><h3 id="paso-1-confirmar-umbrales-de-compresion-y-valores-por-defecto" tabindex="-1">Paso 1: Confirmar Umbrales de Compresión (y Valores por Defecto) <a class="header-anchor" href="#paso-1-confirmar-umbrales-de-compresion-y-valores-por-defecto" aria-label="Permalink to &quot;Paso 1: Confirmar Umbrales de Compresión (y Valores por Defecto)&quot;">​</a></h3><p><strong>Por qué</strong> Los puntos de disparo de compresión no están escritos de forma fija, provienen de <code>proxy.experimental.*</code>. Primero necesitas conocer los umbrales actuales para poder juzgar por qué interviene tan temprano/tarde.</p><p>Valores por defecto (lado Rust <code>ExperimentalConfig::default()</code>):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;proxy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;experimental&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enable_signature_cache&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enable_tool_loop_recovery&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enable_cross_model_checks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enable_usage_scaling&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;context_compression_threshold_l1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;context_compression_threshold_l2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.55</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;context_compression_threshold_l3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.7</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>: Tu configuración contiene <code>proxy.experimental</code> (los nombres de campo son consistentes con lo anterior), y los umbrales son valores de proporción como <code>0.x</code>.</p><div class="warning custom-block"><p class="custom-block-title">La ubicación del archivo de configuración no se repite en esta lección</p><p>La ubicación del archivo de configuración en disco y si es necesario reiniciar después de modificar, pertenece al ámbito de gestión de configuración. Según este sistema de tutoriales, da prioridad a &quot;Configuración Completa: AppConfig/ProxyConfig, Ubicación en Disco y Semántica de Actualización en Caliente&quot;.</p></div><h3 id="paso-2-confirmar-con-registros-si-se-disparan-layer-1-2-3" tabindex="-1">Paso 2: Confirmar con Registros Si Se Disparan Layer 1/2/3 <a class="header-anchor" href="#paso-2-confirmar-con-registros-si-se-disparan-layer-1-2-3" aria-label="Permalink to &quot;Paso 2: Confirmar con Registros Si Se Disparan Layer 1/2/3&quot;">​</a></h3><p><strong>Por qué</strong> Estas tres capas son comportamientos internos del agente, la forma más confiable de verificar es ver si aparecen <code>[Layer-1]</code> / <code>[Layer-2]</code> / <code>[Layer-3]</code> en los registros.</p><p>El plan de pruebas del repositorio proporciona un comando de ejemplo (ajusta según la ruta real de registro en tu máquina):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Application</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Support/com.antigravity.tools/logs/antigravity.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Layer-[123]&quot;</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>: Cuando la presión aumenta, el registro muestra registros similares a <code>Tool trimming triggered</code>, <code>Thinking compression triggered</code>, <code>Fork successful</code> (los campos específicos están sujetos al texto original del registro).</p><h3 id="paso-3-entender-la-diferencia-entre-purificacion-y-compresion-no-mezclar-expectativas" tabindex="-1">Paso 3: Entender la Diferencia Entre Purificación y Compresión (No Mezclar Expectativas) <a class="header-anchor" href="#paso-3-entender-la-diferencia-entre-purificacion-y-compresion-no-mezclar-expectativas" aria-label="Permalink to &quot;Paso 3: Entender la Diferencia Entre Purificación y Compresión (No Mezclar Expectativas)&quot;">​</a></h3><p><strong>Por qué</strong> Algunos problemas (como degradación forzada a modelos que no soportan Thinking) requieren purificación en lugar de compresión. La purificación elimina directamente el bloque Thinking; la compresión preserva la cadena de firmas.</p><p>En el procesador de Claude, la degradación de tareas en segundo plano pasará por <code>ContextManager::purify_history(..., PurificationStrategy::Aggressive)</code>, que eliminará directamente los bloques Thinking históricos.</p><p><strong>Lo que deberías ver</strong>: Puedes distinguir dos tipos de comportamientos:</p><ul><li>La purificación elimina bloques Thinking</li><li>La compresión de Layer 2 reemplaza el texto Thinking antiguo con <code>&quot;...&quot;</code>, pero las firmas aún están presentes</li></ul><h3 id="paso-4-cuando-encuentras-un-error-400-de-firma-primero-revisa-si-hay-hit-en-session-cache" tabindex="-1">Paso 4: Cuando Encuentras un Error 400 de Firma, Primero Revisa Si Hay Hit en Session Cache <a class="header-anchor" href="#paso-4-cuando-encuentras-un-error-400-de-firma-primero-revisa-si-hay-hit-en-session-cache" aria-label="Permalink to &quot;Paso 4: Cuando Encuentras un Error 400 de Firma, Primero Revisa Si Hay Hit en Session Cache&quot;">​</a></h3><p><strong>Por qué</strong> Muchas 400 no son porque no hay firma, sino porque la firma no sigue al mensaje. Durante la conversión de solicitudes, se prioriza recuperar la firma de Session Cache.</p><p>Pistas (los registros en la fase de conversión de solicitudes indicarán recuperación de firmas de SESSION/TOOL cache):</p><ul><li><code>[Claude-Request] Recovered signature from SESSION cache ...</code></li><li><code>[Claude-Request] Recovered signature from TOOL cache ...</code></li></ul><p><strong>Lo que deberías ver</strong>: Cuando el cliente pierde firmas pero el caché del agente aún está, el registro mostrará registros de Recovered signature from ... cache.</p><h3 id="paso-5-entender-que-perdera-la-compresion-de-resultados-de-herramientas" tabindex="-1">Paso 5: Entender Qué Perderá la Compresión de Resultados de Herramientas <a class="header-anchor" href="#paso-5-entender-que-perdera-la-compresion-de-resultados-de-herramientas" aria-label="Permalink to &quot;Paso 5: Entender Qué Perderá la Compresión de Resultados de Herramientas&quot;">​</a></h3><p><strong>Por qué</strong> Si haces que las herramientas devuelvan grandes fragmentos de HTML/instantáneas del navegador/imágenes base64 a la conversación, el agente las eliminará activamente. Necesitas saber de antemano qué contenidos se reemplazarán con marcadores de posición, evitando pensar erróneamente que el modelo no los vio.</p><p>Recuerda tres puntos clave:</p><ol><li>Las imágenes base64 se eliminarán (se cambian a texto de aviso)</li><li>Las instantáneas del navegador se convertirán en resúmenes de head/tail (con indicación de caracteres omitidos)</li><li>Si excede 200,000 caracteres, se truncará y se agregará una indicación <code>...[truncated ...]</code></li></ol><p><strong>Lo que deberías ver</strong>: En <code>tool_result_compressor.rs</code>, estas reglas tienen constantes y ramas explícitas, no se eliminan por experiencia.</p><h2 id="puntos-de-control" tabindex="-1">Puntos de Control <a class="header-anchor" href="#puntos-de-control" aria-label="Permalink to &quot;Puntos de Control&quot;">​</a></h2><ul><li>Puedes explicar claramente que los puntos de disparo de L1/L2/L3 provienen de <code>proxy.experimental.context_compression_threshold_*</code>, por defecto son <code>0.4/0.55/0.7</code></li><li>Puedes explicar por qué Layer 2 romperá el caché: porque modifica el contenido del texto thinking histórico</li><li>Puedes explicar por qué Layer 3 se llama Fork: convierte la conversación en una nueva secuencia de resumen XML + confirmación + mensaje user más reciente</li><li>Puedes explicar que la compresión de resultados de herramientas eliminará imágenes base64 y convertirá instantáneas del navegador en resúmenes de head/tail</li></ul><h2 id="advertencias-sobre-problemas-comunes" tabindex="-1">Advertencias Sobre Problemas Comunes <a class="header-anchor" href="#advertencias-sobre-problemas-comunes" aria-label="Permalink to &quot;Advertencias Sobre Problemas Comunes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fenómeno</th><th>Causa Posible</th><th>Qué Puedes Hacer</th></tr></thead><tbody><tr><td>Después de disparar Layer 2 sientes que el contexto no es tan estable</td><td>Layer 2 modifica el contenido histórico, los comentarios indican explícitamente que romperá el caché</td><td>Si dependes de la consistencia de Prompt Cache, deja que L1 resuelva el problema primero, o aumenta el umbral L2</td></tr><tr><td>Después de disparar Layer 3 se devuelve directamente 400</td><td>Fork + resumen falló la llamada al modelo en segundo plano (red/cuenta/error upstream, etc.)</td><td>Primero usa <code>/compact</code> o <code>/clear</code> según la sugerencia en el error JSON; al mismo tiempo verifica la ruta de llamada del modelo en segundo plano</td></tr><tr><td>Imágenes/contenido grande desaparecen en la salida de herramientas</td><td>tool_result eliminará imágenes base64, truncará salidas excesivamente largas</td><td>Guarda el contenido importante en archivos locales/enlaces y luego reférencia; no esperes meter 100,000 líneas de texto directamente en la conversación</td></tr><tr><td>Explícitamente estás usando el modelo Gemini pero llevas firmas de Claude causando errores</td><td>Las firmas no son compatibles entre modelos (en el código hay verificación de family)</td><td>Confirma el origen de la firma; si es necesario, deja que el agente elimine firmas históricas en escenarios de retry (ver lógica de conversión de solicitudes)</td></tr></tbody></table><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de Esta Lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de Esta Lección&quot;">​</a></h2><ul><li>El núcleo de la compresión de tres capas es clasificar por costo: primero eliminar rondas antiguas de herramientas, luego comprimir Thinking antiguo, y finalmente Fork + resumen XML</li><li>El caché de firmas es clave para que la cadena de herramientas no se rompa: tres capas Session/Tool/Family cada una maneja un tipo de problema, TTL es 2 horas</li><li>La compresión de resultados de herramientas es el límite duro para evitar que la salida de herramientas sature el contexto: límite superior de 200,000 caracteres + especialización para instantáneas/archivos grandes</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima Lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima Lección&quot;">​</a></h2><blockquote><p>En la próxima lección hablaremos de capacidades del sistema: multilingüismo/temas/actualizaciones/inicio automático/Servidor HTTP API.</p></blockquote><hr><h2 id="apendice-referencias-de-codigo-fuente" tabindex="-1">Apéndice: Referencias de Código Fuente <a class="header-anchor" href="#apendice-referencias-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencias de Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir ubicaciones de código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del Archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>Configuración experimental: umbrales de compresión y valores por defecto de interruptores</td><td><code>src-tauri/src/proxy/config.rs</code></td><td>119-168</td></tr><tr><td>Estimación de contexto: estimación de caracteres multilingüe + 15% de margen</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>9-37</td></tr><tr><td>Estimación de uso de tokens: iterar sobre system/messages/tools/thinking</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>103-198</td></tr><tr><td>Layer 1: identificar rondas de herramientas + recortar rondas antiguas</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>311-439</td></tr><tr><td>Layer 2: compresión de Thinking pero preservación de firmas (proteger los últimos N mensajes)</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>200-271</td></tr><tr><td>Auxiliar de Layer 3: extraer la última firma válida</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>73-109</td></tr><tr><td>Degradación de tareas en segundo plano: purificación agresiva de bloques Thinking</td><td><code>src-tauri/src/proxy/handlers/claude.rs</code></td><td>540-583</td></tr><tr><td>Flujo principal de compresión de tres capas: estimación, calibración, disparo L1/L2/L3 por umbral</td><td><code>src-tauri/src/proxy/handlers/claude.rs</code></td><td>379-731</td></tr><tr><td>Layer 3: implementación de resumen XML + Fork de sesión</td><td><code>src-tauri/src/proxy/handlers/claude.rs</code></td><td>1560-1687</td></tr><tr><td>Caché de firmas: TTL/estructura de caché de tres capas (Tool/Family/Session)</td><td><code>src-tauri/src/proxy/signature_cache.rs</code></td><td>5-88</td></tr><tr><td>Caché de firmas: escritura/lectura de firma Session</td><td><code>src-tauri/src/proxy/signature_cache.rs</code></td><td>141-223</td></tr><tr><td>Análisis de flujo SSE: cachear signature de thinking/tool en Session/Tool cache</td><td><code>src-tauri/src/proxy/mappers/claude/streaming.rs</code></td><td>766-776</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Conversión de solicitudes: tool_use recupera firma de Session/Tool cache</td><td><code>src-tauri/src/proxy/mappers/claude/request.rs</code></td><td>1045-1142</td></tr><tr><td>Conversión de solicitudes: tool_result dispara compresión de resultados de herramientas</td><td><code>src-tauri/src/proxy/mappers/claude/request.rs</code></td><td>1159-1225</td></tr><tr><td>Compresión de resultados de herramientas: entrada <code>compact_tool_result_text()</code></td><td><code>src-tauri/src/proxy/mappers/tool_result_compressor.rs</code></td><td>28-69</td></tr><tr><td>Compresión de resultados de herramientas: resumen head/tail de instantáneas del navegador</td><td><code>src-tauri/src/proxy/mappers/tool_result_compressor.rs</code></td><td>123-178</td></tr><tr><td>Compresión de resultados de herramientas: eliminar imágenes base64 + límite total de caracteres</td><td><code>src-tauri/src/proxy/mappers/tool_result_compressor.rs</code></td><td>247-320</td></tr><tr><td>Plan de pruebas: disparo de compresión de tres capas y verificación de registros</td><td><code>docs/testing/context_compression_test_plan.md</code></td><td>1-116</td></tr></tbody></table></details>`,77)])])}const h=a(o,[["render",t]]);export{u as __pageData,h as default};
